<script>
(function() {
  'use strict';

  // ── Clock ──
  function updateClock() {
    const now = new Date();
    document.getElementById('clock').textContent = now.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' }) + '  ' + now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
  }
  updateClock();
  setInterval(updateClock, 10000);

  // ── Filesystem data ──
  const fs = {
    '/': { type: 'dir', children: ['bin','etc','home','usr','var'] },
    '/bin': { type: 'dir', children: ['bash','ls','cp','mv','rm','cat'] },
    '/etc': { type: 'dir', children: ['passwd','hostname','fstab','hosts','resolv.conf'] },
    '/home': { type: 'dir', children: ['user'] },
    '/usr': { type: 'dir', children: ['bin','lib','share','local'] },
    '/var': { type: 'dir', children: ['log','cache','tmp','mail'] },
    '/home/user': { type: 'dir', children: ['Documents','Downloads','Pictures','.bashrc','.profile'] },
    '/home/user/Documents': { type: 'dir', children: ['notes.txt','todo.md','report.pdf'] },
    '/home/user/Downloads': { type: 'dir', children: ['ubuntu.iso','archive.tar.gz','image.png'] },
    '/home/user/Pictures': { type: 'dir', children: ['wallpaper.jpg','screenshot.png','.gitkeep'] },
    '/bin/bash': { type: 'file' },
    '/bin/ls': { type: 'file' },
    '/bin/cp': { type: 'file' },
    '/bin/mv': { type: 'file' },
    '/bin/rm': { type: 'file' },
    '/bin/cat': { type: 'file' },
    '/etc/passwd': { type: 'file' },
    '/etc/hostname': { type: 'file' },
    '/etc/fstab': { type: 'file' },
    '/etc/hosts': { type: 'file' },
    '/etc/resolv.conf': { type: 'file' },
    '/usr/bin': { type: 'dir', children: ['python3','gcc','make'] },
    '/usr/lib': { type: 'dir', children: ['libc.so','libpthread.so'] },
    '/usr/share': { type: 'dir', children: ['man','doc','locale'] },
    '/usr/local': { type: 'dir', children: ['bin','lib'] },
    '/var/log': { type: 'dir', children: ['syslog','auth.log','kern.log'] },
    '/var/cache': { type: 'dir', children: ['apt','pip'] },
    '/var/tmp': { type: 'dir', children: [] },
    '/var/mail': { type: 'dir', children: ['user'] },
    '/usr/bin/python3': { type: 'file' },
    '/usr/bin/gcc': { type: 'file' },
    '/usr/bin/make': { type: 'file' },
    '/usr/lib/libc.so': { type: 'file' },
    '/usr/lib/libpthread.so': { type: 'file' },
    '/var/log/syslog': { type: 'file' },
    '/var/log/auth.log': { type: 'file' },
    '/var/log/kern.log': { type: 'file' },
    '/home/user/.bashrc': { type: 'file' },
    '/home/user/.profile': { type: 'file' },
    '/home/user/Documents/notes.txt': { type: 'file' },
    '/home/user/Documents/todo.md': { type: 'file' },
    '/home/user/Documents/report.pdf': { type: 'file' },
    '/home/user/Downloads/ubuntu.iso': { type: 'file' },
    '/home/user/Downloads/archive.tar.gz': { type: 'file' },
    '/home/user/Downloads/image.png': { type: 'file' },
    '/home/user/Pictures/wallpaper.jpg': { type: 'file' },
    '/home/user/Pictures/screenshot.png': { type: 'file' },
  };

  // ── Files app state ──
  let currentPath = '/';

  function getIcon(name) {
    if (fs[name] && fs[name].type === 'dir') return '📁';
    const ext = name.split('.').pop().toLowerCase();
    const icons = { txt:'📄', md:'📝', pdf:'📕', iso:'💿', tar:'🗜️', gz:'🗜️', png:'🖼️', jpg:'🖼️', jpeg:'🖼️', gif:'🖼️', svg:'🖼️', sh:'🐚', conf:'⚙️', log:'📋', json:'📦', py:'🐍', html:'🌐', css:'🎨', js:'📜' };
    return icons[ext] || '📄';
  }

  function renderFiles() {
    const body = document.getElementById('files-body');
    const pathInput = document.getElementById('files-path');
    pathInput.value = currentPath;

    body.innerHTML = '';
    const entry = fs[currentPath];
    if (!entry || entry.type !== 'dir') return;

    // Sort: directories first, then files
    const children = (entry.children || []).slice().sort((a, b) => {
      const aDir = (fs[a] && fs[a].type === 'dir') ? 0 : 1;
      const bDir = (fs[b] && fs[b].type === 'dir') ? 0 : 1;
      if (aDir !== bDir) return aDir - bDir;
      return a.localeCompare(b);
    });

    for (const child of children) {
      const item = document.createElement('div');
      item.className = 'fs-item';

      const iconEl = document.createElement('div');
      iconEl.className = 'icon';
      iconEl.textContent = getIcon(child);

      const nameEl = document.createElement('div');
      nameEl.className = 'name';
      nameEl.textContent = child;

      item.appendChild(iconEl);
      item.appendChild(nameEl);

      // Double-click to navigate into folders
      let clickTimer = null;
      item.addEventListener('click', function() {
        if (clickTimer) { clearTimeout(clickTimer); clickTimer = null; return; }
        clickTimer = setTimeout(function() {
          clickTimer = null;
        }, 250);
      });

      item.addEventListener('dblclick', function(e) {
        e.preventDefault();
        if (clickTimer) { clearTimeout(clickTimer); clickTimer = null; }
        const fullPath = currentPath === '/' ? '/' + child : currentPath + '/' + child;
        if (fs[fullPath] && fs[fullPath].type === 'dir') {
          currentPath = fullPath;
          renderFiles();
        }
      });

      body.appendChild(item);
    }
  }

  document.getElementById('files-up').addEventListener('click', function() {
    if (currentPath === '/') return;
    const parts = currentPath.split('/').filter(Boolean);
    parts.pop();
    currentPath = '/' + parts.join('/') || '/';
    renderFiles();
  });

  // ── Notepad app state & persistence ──
  const STORAGE_KEY = 'notepad-tabs-v1';

  function loadTabs() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) return JSON.parse(raw);
    } catch(e) {}
    return [];
  }

  function saveTabs(tabs) {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(tabs));
    } catch(e) {}
  }

  let tabs = loadTabs();
  let activeTabIndex = -1;

  function ensureAtLeastOneTab() {
    if (tabs.length === 0) {
      tabs.push({ name: 'Untitled', content: '' });
      saveTabs(tabs);
    }
    if (activeTabIndex < 0 || activeTabIndex >= tabs.length) {
      activeTabIndex = tabs.length - 1;
    }
  }

  function renderTabs() {
    ensureAtLeastOneTab();
    const container = document.getElementById('tabs');
    container.innerHTML = '';

    for (let i = 0; i < tabs.length; i++) {
      const tab = document.createElement('div');
      tab.className = 'tab' + (i === activeTabIndex ? ' active' : '');
      tab.dataset.index = i;

      const nameEl = document.createElement('span');
      nameEl.textContent = tabs[i].name;
      nameEl.style.overflow = 'hidden';
      nameEl.style.textOverflow = 'ellipsis';
      nameEl.style.whiteSpace = 'nowrap';

      const closeBtn = document.createElement('button');
      closeBtn.className = 'close-tab';
      closeBtn.innerHTML = '✕';
      closeBtn.addEventListener('click', function(e) {
        e.stopPropagation();
        removeTab(i);
      });

      tab.appendChild(nameEl);
      tab.appendChild(closeBtn);

      tab.addEventListener('click', function() {
        if (i !== activeTabIndex) {
          activeTabIndex = i;
          renderTabs();
          document.getElementById('editor').value = tabs[i].content;
        }
      });

      container.appendChild(tab);
    }

    // Update editor
    const editor = document.getElementById('editor');
    if (activeTabIndex >= 0 && activeTabIndex < tabs.length) {
      editor.value = tabs[activeTabIndex].content;
    }
  }

  function removeTab(index) {
    if (tabs.length <= 1) return; // Keep at least one tab
    tabs.splice(index, 1);
    saveTabs(tabs);
    if (activeTabIndex >= tabs.length) activeTabIndex = tabs.length - 1;
    renderTabs();
  }

  document.getElementById('new-tab').addEventListener('click', function() {
    const idx = tabs.length;
    tabs.push({ name: 'Untitled', content: '' });
    saveTabs(tabs);
    activeTabIndex = idx;
    renderTabs();
    document.getElementById('editor').focus();
  });

  // Save on typing (debounced)
  let saveTimeout = null;
  document.getElementById('editor').addEventListener('input', function() {
    if (activeTabIndex >= 0 && activeTabIndex < tabs.length) {
      tabs[activeTabIndex].content = this.value;
      clearTimeout(saveTimeout);
      saveTimeout = setTimeout(function() { saveTabs(tabs); }, 400);
    }
  });

  // ── Window management ──
  const filesWindow = document.getElementById('files-window');
  const notepadWindow = document.getElementById('notepad-window');

  function showFiles() {
    filesWindow.classList.remove('hidden');
    renderFiles();
  }

  function hideFiles() {
    filesWindow.classList.add('hidden');
  }

  function showNotepad() {
    notepadWindow.classList.remove('hidden');
    ensureAtLeastOneTab();
    renderTabs();
  }

  function hideNotepad() {
    notepadWindow.classList.add('hidden');
  }

  document.getElementById('open-files').addEventListener('click', showFiles);
  document.getElementById('open-notepad').addEventListener('click', showNotepad);

  // Close buttons
  filesWindow.querySelector('.win-close').addEventListener('click', hideFiles);
  notepadWindow.querySelector('.win-close').addEventListener('click', hideNotepad);

  // ── Dragging windows ──
  let dragTarget = null;
  let dragOffsetX = 0, dragOffsetY = 0;
  let isDragging = false;

  document.querySelectorAll('[data-drag]').forEach(function(titlebar) {
    titlebar.addEventListener('mousedown', function(e) {
      if (e.target.closest('.win-close')) return;
      const winId = this.getAttribute('data-drag');
      dragTarget = document.getElementById(winId);
      if (!dragTarget || dragTarget.classList.contains('hidden')) { dragTarget = null; return; }

      isDragging = true;
      dragOffsetX = e.clientX - dragTarget.offsetLeft;
      dragOffsetY = e.clientY - dragTarget.offsetTop;
      dragTarget.classList.add('dragging');
      e.preventDefault();
    });
  });

  document.addEventListener('mousemove', function(e) {
    if (!isDragging || !dragTarget) return;
    let x = e.clientX - dragOffsetX;
    let y = e.clientY - dragOffsetY;
    // Clamp within viewport
    const maxW = window.innerWidth - 40;
    const maxH = window.innerHeight - 100;
    if (x < 0) x = 0;
    if (y < 28) y = 28;
    if (x > maxW) x = maxW;
    if (y > maxH) y = maxH;
    dragTarget.style.left = x + 'px';
    dragTarget.style.top = y + 'px';
  });

  document.addEventListener('mouseup', function() {
    if (dragTarget) dragTarget.classList.remove('dragging');
    isDragging = false;
    dragTarget = null;
  });

  // ── Init ──
  renderFiles();
})();
</script>
